// Kenya — government software-development opportunity queries.
// Discovery backend: SearXNG (open-source metasearch). Point this at your instance:
//   • preferred: set an n8n env var  SEARXNG_URL=https://searx.example.org
//   • or just edit the `base` fallback on the next line.
let base = 'http://searxng:8080';
try { if ($env && $env.SEARXNG_URL) base = $env.SEARXNG_URL; } catch (e) {}
base = String(base).replace(/\/+$/, '');

// Edit / add queries freely. SearXNG honours the site: and OR operators.
const queries = [
  '("software development" OR "system development" OR "application development" OR "information system") (tender OR "request for proposal" OR "expression of interest" OR prequalification) site:go.ke',
  '(software OR ICT OR "e-government" OR digital OR automation OR ERP) (tender OR EOI OR RFP OR "request for proposal") (county OR ministry OR authority OR parastatal) Kenya',
  'software development tender site:tenders.go.ke',
  '("request for proposal" OR "expression of interest" OR prequalification) (software OR "information system" OR ERP OR portal) county government Kenya',
  '(software OR "management system" OR "web application" OR "mobile application") (tender OR procurement) ("national treasury" OR ministry OR county OR commission) Kenya',
];

return queries.map((q) => {
  const url = base + '/search?q=' + encodeURIComponent(q) +
    '&format=json&language=en-KE&safesearch=0&time_range=month';
  return { json: { q, url, stream: 'KE' } };
});

// Flatten SearXNG results, normalize, and keep only relevant hits.
// Relevance = (a primary keyword) AND (a context keyword), minus an exclude list.
// Branches on item.json.stream so the same node works for both streams.
const KW = {
  KE: {
    primary: ['software','application development','app development','system development',
      'information system','management system','ict','e-government','egovernment','digital service',
      'automation','erp','web application','web-based','mobile application','platform','api','integration',
      'bespoke','custom system','portal','database system','enterprise system','source code','saas'],
    context: ['tender','rfp','request for proposal','rfq','request for quotation','expression of interest',
      'eoi','prequalification','pre-qualification','bid','procurement','solicitation','invitation to tender',
      '.go.ke','county','ministry','authority','national treasury','huduma'],
    exclude: [],
  },
  US: {
    primary: ['reconciliation','reconcile','reconciling','bank reconciliation','account reconciliation',
      'financial reconciliation','cash reconciliation','gl reconciliation','general ledger reconciliation',
      'treasury reconciliation','payment reconciliation','ledger reconciliation'],
    context: ['rfp','rfq','request for proposal','request for qualifications','itb','ifb','invitation to bid',
      'solicitation','bid','procurement','rfi','.gov','city','county','state','municipal','treasurer',
      'comptroller','controller','finance department'],
    exclude: ['sam.gov','grants.gov','beta.sam.gov'],
  },
};

const out = [];
for (const item of $input.all()) {
  const stream = item.json.stream || 'KE';
  const cfg = KW[stream] || KW.KE;
  const results = Array.isArray(item.json.results) ? item.json.results : [];
  for (const r of results) {
    const url = r.url || '';
    const title = r.title || '';
    const snippet = r.content || '';
    if (!url || !title) continue;
    const hay = (title + ' ' + snippet + ' ' + url).toLowerCase();
    if (cfg.exclude.some((x) => hay.includes(x))) continue;
    const hasPrimary = cfg.primary.some((x) => hay.includes(x));
    const hasContext = cfg.context.some((x) => hay.includes(x));
    if (!(hasPrimary && hasContext)) continue;
    let domain = '';
    try { domain = new URL(url).hostname.replace(/^www\./, ''); } catch (e) {}
    const matched = cfg.primary.filter((x) => hay.includes(x)).slice(0, 4);
    out.push({ json: {
      stream, title: title.trim(), url, snippet: snippet.trim(),
      domain, engine: r.engine || '', matched, query: item.json.q,
    } });
  }
}
return out;

// De-duplicate against everything seen on previous runs.
// Uses n8n workflow static data (persists only when the workflow is ACTIVE and
// fired by its trigger — not on manual test executions).
const staticData = $getWorkflowStaticData('global');
const items = $input.all();
const stream = items.length ? (items[0].json.stream || 'KE') : 'KE';
const key = 'seen_' + stream;
const seen = (staticData[key] = staticData[key] || {});

const now = Date.now();
const out = [];
for (const item of items) {
  const url = item.json.url;
  if (!url) continue;
  if (!seen[url]) {
    seen[url] = now;
    out.push(item);
  }
}

// Prune entries older than 90 days so static data can't grow forever.
const cutoff = now - 90 * 24 * 60 * 60 * 1000;
for (const k of Object.keys(seen)) {
  if (seen[k] < cutoff) delete seen[k];
}

return out;

// Build a single HTML digest item from the new results.
// Returns [] when there is nothing new, so the email node simply doesn't fire.
const items = $input.all();
if (!items.length) return [];

function escapeHtml(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;')
    .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

const stream = items[0].json.stream || 'KE';
const titleMap = {
  KE: 'Kenya \u2014 government software-development opportunities',
  US: 'US state & city \u2014 reconciliation solicitations',
};
const heading = titleMap[stream] || 'Opportunities';
const today = new Date().toISOString().slice(0, 10);
const count = items.length;

const rowsHtml = items.map((i) => {
  const j = i.json;
  const tags = (j.matched && j.matched.length) ? j.matched.join(', ') : '';
  return [
    '<tr><td style="padding:10px 12px;border-bottom:1px solid #e3e8ea;vertical-align:top;">',
    '<a href="' + j.url + '" style="color:#1F6F78;font-weight:bold;text-decoration:none;font-size:15px;">' + escapeHtml(j.title) + '</a>',
    '<div style="color:#5C6B70;font-size:12px;margin:2px 0 6px;">' + escapeHtml(j.domain || '') +
      (tags ? ' &nbsp;\u00b7&nbsp; matched: ' + escapeHtml(tags) : '') + '</div>',
    '<div style="color:#1A2B30;font-size:13px;line-height:1.45;">' + escapeHtml((j.snippet || '').slice(0, 280)) + '</div>',
    '</td></tr>',
  ].join('');
}).join('');

const html = [
  '<div style="font-family:Arial,Helvetica,sans-serif;max-width:720px;margin:0 auto;">',
  '<h2 style="color:#13343B;margin:0 0 4px;">' + heading + '</h2>',
  '<div style="color:#5C6B70;font-size:13px;margin-bottom:14px;">' + count + ' new result' + (count === 1 ? '' : 's') + ' \u00b7 ' + today + '</div>',
  '<table style="width:100%;border-collapse:collapse;border:1px solid #e3e8ea;">' + rowsHtml + '</table>',
  '<p style="color:#9aa7ab;font-size:11px;margin-top:14px;">Automated scan via n8n + SearXNG. Verify each opportunity on the issuing portal before acting; results are de-duplicated against prior runs.</p>',
  '</div>',
].join('');

const subject = '[' + stream + '] ' + heading + ' \u2014 ' + count + ' new (' + today + ')';

return [{ json: { subject, html, count, stream } }];

